solution_code:
#include <stdio.h>
#include <pthread.h>

void *print_num(void *arg) {
    int num = *(int *)arg;
    printf("Thread got: %d\n", num);
    return NULL;
}

int main(void) {
    pthread_t t1, t2;
    int a = 10, b = 20;
    pthread_create(&t1, NULL, print_num, &a);
    pthread_join(t1, NULL);
    pthread_create(&t2, NULL, print_num, &b);
    pthread_join(t2, NULL);
    printf("Done.\n");
    return 0;
}

